<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>2048</title>
<style>
  :root {
    --bg: #121212;
    --board-bg: #1e1e1e;
    --cell-bg: #2a2a2a;
    --text: #f1f1f1;
  }
  * { box-sizing: border-box; }
  body {
    margin: 0;
    min-height: 100vh;
    background: var(--bg);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: 16px;
    padding: 20px;
  }
  h1 {
    margin: 0;
    font-size: 2.5em;
    letter-spacing: 2px;
  }
  .top-bar {
    display: flex;
    align-items: center;
    gap: 16px;
  }
  #score-box {
    background: var(--board-bg);
    border-radius: 8px;
    padding: 10px 20px;
    text-align: center;
    min-width: 100px;
  }
  #score-box .label {
    font-size: 0.75em;
    color: #999;
    text-transform: uppercase;
    letter-spacing: 1px;
  }
  #score {
    font-size: 1.5em;
    font-weight: bold;
  }
  #reset {
    background: #f67c5f;
    color: white;
    border: none;
    border-radius: 8px;
    padding: 12px 20px;
    font-size: 1em;
    font-weight: bold;
    cursor: pointer;
  }
  #reset:hover {
    background: #f4602e;
  }
  #board {
    display: grid;
    grid-template-columns: repeat(4, 80px);
    grid-template-rows: repeat(4, 80px);
    gap: 10px;
    background: var(--board-bg);
    padding: 10px;
    border-radius: 10px;
  }
  .cell {
    width: 80px;
    height: 80px;
    background: var(--cell-bg);
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 1.6em;
    font-weight: bold;
    color: var(--text);
    transition: background 0.1s ease;
  }
  .cell[data-value="0"] { color: transparent; }
  .cell[data-value="2"] { background: #3a3a3a; }
  .cell[data-value="4"] { background: #4a4530; }
  .cell[data-value="8"] { background: #b06a3a; color: #fff; }
  .cell[data-value="16"] { background: #c17b3f; color: #fff; }
  .cell[data-value="32"] { background: #cc6d4f; color: #fff; }
