  }
</style>
</head>
<body>
  <h1>2048</h1>
  <div class="top-bar">
    <div id="score-box">
      <div class="label">Score</div>
      <div id="score">0</div>
    </div>
    <button id="reset">New Game</button>
  </div>
  <div id="board"></div>
  <div id="hint">Use arrow keys to play</div>

<script>
(function () {
  const SIZE = 4;
  let grid = [];
  let currentScore = 0;

  const boardEl = document.getElementById('board');
  const scoreEl = document.getElementById('score');
  const resetBtn = document.getElementById('reset');

  function emptyGrid() {
    return Array.from({ length: SIZE }, () => Array(SIZE).fill(0));
  }

  function cloneGrid(g) {
    return g.map(row => row.slice());
  }

  function gridsEqual(a, b) {
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        if (a[r][c] !== b[r][c]) return false;
      }
    }
    return true;
  }

  function getEmptyCells(g) {
    const cells = [];
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        if (g[r][c] === 0) cells.push([r, c]);
      }
    }
    return cells;
  }

  function spawnTile(g) {
    const empties = getEmptyCells(g);
    if (empties.length === 0) return false;
    const [r, c] = empties[Math.floor(Math.random() * empties.length)];
    g[r][c] = Math.random() < 0.9 ? 2 : 4;
    return true;
  }

  function render() {
    boardEl.innerHTML = '';
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        const val = grid[r][c];
        const cell = document.createElement('div');
        cell.className = 'cell';
        cell.dataset.value = String(val);
        cell.textContent = val === 0 ? '' : String(val);
        boardEl.appendChild(cell);
      }
    }
    scoreEl.textContent = String(currentScore);
  }

  // Slide+merge a single row to the left. Returns { row, gained }.
  function slideRowLeft(row) {
    let arr = row.filter(v => v !== 0);
    let gained = 0;
    for (let i = 0; i < arr.length - 1; i++) {
      if (arr[i] !== 0 && arr[i] === arr[i + 1]) {
        arr[i] = arr[i] * 2;
        gained += arr[i];
        arr[i + 1] = 0;
        i++; // this tile already merged, skip past it
      }
    }
    arr = arr.filter(v => v !== 0);
    while (arr.length < SIZE) arr.push(0);
    return { row: arr, gained };
  }

  function transpose(g) {
    const t = emptyGrid();
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        t[c][r] = g[r][c];
      }
    }
    return t;
  }

  function reverseRows(g) {
    return g.map(row => row.slice().reverse());
  }

  function applyMove(g, direction) {
    let working = cloneGrid(g);
    let transposed = false;
    let reversed = false;

    if (direction === 'up' || direction === 'down') {
      working = transpose(working);
      transposed = true;
    }
    if (direction === 'right' || direction === 'down') {
      working = reverseRows(working);
      reversed = true;
    }

    let totalGained = 0;
    for (let r = 0; r < SIZE; r++) {
      const { row, gained } = slideRowLeft(working[r]);
      working[r] = row;
      totalGained += gained;
    }

    if (reversed) working = reverseRows(working);
    if (transposed) working = transpose(working);

    return { grid: working, gained: totalGained };
  }

  function move(direction) {
    if (!['left', 'right', 'up', 'down'].includes(direction)) return false;
    const result = applyMove(grid, direction);
    const changed = !gridsEqual(grid, result.grid);
    if (changed) {
      grid = result.grid;
      currentScore += result.gained;
      spawnTile(grid);
      render();
    }
    return changed;
  }

  function reset() {
    grid = emptyGrid();
    currentScore = 0;
    spawnTile(grid);
    spawnTile(grid);
    render();
  }

  function setBoard(arr) {
    const g = emptyGrid();
    for (let r = 0; r < SIZE; r++) {
      for (let c = 0; c < SIZE; c++) {
        g[r][c] = (arr[r] && typeof arr[r][c] === 'number') ? arr[r][c] : 0;
      }
    }
    grid = g;
    render();
  }

  function board() {
    return grid.map(row => row.slice());
  }

  function score() {
    return currentScore;
  }

  window.game = {
    size: SIZE,
    reset,
    move,
    board,
    setBoard,
    score,
  };

  resetBtn.addEventListener('click', reset);

  const keyMap = {
    ArrowLeft: 'left',
    ArrowRight: 'right',
    ArrowUp: 'up',
    ArrowDown: 'down',
  };

  document.addEventListener('keydown', (e) => {
    const dir = keyMap[e.key];
    if (dir) {
      e.preventDefault();
      move(dir);
    }
  });

  reset();
})();
</script>
</body>
</html>
